const payload = $json.payload || {};
const customerName = payload.customer_name || 'Customer';
const providerName = payload.provider_name || 'Provider';
const orderCode = payload.order_code || 'N/A';
const estimatedPrice = payload.estimated_price ?? 0;
const dpAmount = payload.dp_amount ?? 0;
const customerPhone = payload.customer_phone || '';
const providerPhone = payload.provider_phone || '';

return [
  {
    json: {
      phone: customerPhone,
      recipient_type: 'customer',
      message: `Halo ${customerName}, pesanan *${orderCode}* sudah dibuat. Estimasi harga Rp ${estimatedPrice}. Silakan tunggu konfirmasi provider.\n\nKode Order: ${orderCode}\nTotal DP: Rp ${dpAmount}`
    }
  },
  {
    json: {
      phone: providerPhone,
      recipient_type: 'provider',
      message: `Halo ${providerName}, ada order baru *${orderCode}*. Silakan cek detail pesanan dan segera respon.`
    }
  }
];

